import { useState, useEffect, useRef } from "react";
import "./Portfolio.css";

const PROFILE_PHOTO = "data:image/png;base64,";
const RESUME_PDF    = "data:application/pdf;base64,";

const NAV_LINKS = ["Home", "About", "Skills", "Projects", "Contact"];

const SKILLS = {
  Languages:             ["JavaScript", "PHP", "HTML", "CSS", "C/C++", "Java", "SQL"],
  "Frameworks/Libraries":["React.js", "Express.js", "Node.js"],
  Databases:             ["MongoDB", "MySQL"],
  Tools:                 ["VS Code", "GitHub", "Postman"],
};

const PROJECTS = [
  {
    name: "CampusRide",
    tag: "MERN Stack",
    color: "#00f5a0",
    description: "A ride-sharing platform for campus commuting built with the MERN stack. Connects students for efficient, eco-friendly travel with real-time ride coordination.",
    tech: ["MongoDB", "Express.js", "React.js", "Node.js"],
    icon: "🎓",
    highlights: [
      "Real-time ride coordination to connect students for campus commuting",
      "Role-based authentication for students and admins",
      "Scalable backend with RESTful APIs for user requests and ride matching",
      "Eco-friendly travel solution reducing individual commute costs",
      "Responsive React frontend with dynamic routing",
    ],
    github: "https://github.com/Vansh-dev1/CampusRide",
  },
  {
    name: "BlogX",
    tag: "Web Dev",
    color: "#f5a623",
    description: "A dynamic blog platform where users can create, edit, and share articles. Built with a classic web stack featuring a clean reading experience and rich text publishing.",
    tech: ["HTML", "CSS", "JavaScript", "PHP"],
    icon: "✍️",
    highlights: [
      "User registration, login & session management with PHP",
      "Rich text editor for writing and formatting posts",
      "Comment system with user interactions",
      "Search and category filtering for articles",
      "MySQL database for persistent storage",
    ],
    github: "https://github.com/Vansh-dev1",
  },
];

/* ─── Main Component ──────────────────────────────────────────────────────── */
export default function Portfolio() {
  const [active, setActive]               = useState("Home");
  const [menuOpen, setMenuOpen]           = useState(false);
  const [selectedProject, setSelectedProject] = useState(null);
  const [typed, setTyped]                 = useState("");
  const [formData, setFormData]           = useState({ name: "", email: "", message: "" });
  const [sent, setSent]                   = useState(false);
  const [sending, setSending]             = useState(false);
  const [formError, setFormError]         = useState("");

  const roles    = ["Full Stack Developer", "MERN Enthusiast", "B.TECH Student", "Problem Solver"];
  const roleIdx  = useRef(0);
  const charIdx  = useRef(0);
  const deleting = useRef(false);

  // Typewriter effect
  useEffect(() => {
    const interval = setInterval(() => {
      const role = roles[roleIdx.current];
      if (!deleting.current) {
        setTyped(role.slice(0, charIdx.current + 1));
        charIdx.current++;
        if (charIdx.current === role.length) {
          deleting.current = true;
          clearInterval(interval);
          setTimeout(() => { deleting.current = true; }, 1200);
        }
      }
    }, 80);
    const delInterval = setInterval(() => {
      if (deleting.current) {
        const role = roles[roleIdx.current];
        setTyped(role.slice(0, charIdx.current - 1));
        charIdx.current--;
        if (charIdx.current === 0) {
          deleting.current = false;
          roleIdx.current = (roleIdx.current + 1) % roles.length;
        }
      }
    }, 45);
    return () => { clearInterval(interval); clearInterval(delInterval); };
  }, []);

  const scrollTo = (section) => {
    setActive(section);
    setMenuOpen(false);
    document.getElementById(section)?.scrollIntoView({ behavior: "smooth" });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSending(true);
    setFormError("");
    try {
      const res  = await fetch("http://localhost:3001/api/contact", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      });
      const data = await res.json();
      if (data.success) {
        setSent(true);
        setFormData({ name: "", email: "", message: "" });
        setTimeout(() => setSent(false), 4000);
      } else {
        setFormError(data.error || "Something went wrong. Please try again.");
      }
    } catch {
      setFormError("Could not reach the server. Make sure the backend is running.");
    } finally {
      setSending(false);
    }
  };

  return (
    <div className="portfolio-root">
      <div className="bg-grid" />
      <div className="bg-glow-1" />
      <div className="bg-glow-2" />

      {/* ── NAVBAR ── */}
      <nav className="nav">
        <div className="nav-logo">
          <span className="logo-angle">&lt;</span>
          <span className="logo-name">Portfolio</span>
          <span className="logo-angle">/&gt;</span>
        </div>
        <div className="nav-links">
          {NAV_LINKS.map((l) => (
            <button
              key={l}
              onClick={() => scrollTo(l)}
              className={`nav-btn ${active === l ? "active" : ""}`}
            >
              {l}
              {active === l && <span className="nav-underline" />}
            </button>
          ))}
        </div>
        <a href={RESUME_PDF} download="Vansh_Lunagariya_Resume.pdf" className="resume-btn">
          ↓ Resume
        </a>
        <button className="hamburger" onClick={() => setMenuOpen(!menuOpen)}>
          {menuOpen ? "✕" : "☰"}
        </button>
      </nav>

      {menuOpen && (
        <div className="mobile-menu">
          {NAV_LINKS.map((l) => (
            <button key={l} onClick={() => scrollTo(l)} className="mobile-menu-btn">{l}</button>
          ))}
        </div>
      )}

      {/* ── HERO ── */}
      <section id="Home" className="hero">
        <div className="hero-content">
          <p className="hero-greet">👋 Hello, I'm</p>
          <h1 className="hero-name">Vansh Lunagariya</h1>
          <div className="hero-badge">
            <span className="hero-cursor">▍</span>
            <span className="hero-role">{typed}</span>
          </div>
          <p className="hero-sub">
            3rd Year B.TECH Student @ <span className="highlight">ADIT College</span> · Building impactful web experiences with the MERN stack.
          </p>
          <div className="hero-btns">
            <button onClick={() => scrollTo("Projects")} className="btn-primary">View Projects</button>
            <button onClick={() => scrollTo("Contact")}  className="btn-outline">Contact Me</button>
            <a href={RESUME_PDF} download="Vansh_Lunagariya_Resume.pdf" className="btn-resume">↓ Resume</a>
          </div>
        </div>
        <div className="hero-visual">
          <PhotoFrame photo={PROFILE_PHOTO} />
        </div>
      </section>

      {/* ── ABOUT ── */}
      <section id="About" className="section">
        <SectionTitle label="01" title="About Me" />
        <div className="about-grid">
          <AboutCard />
          <div className="about-text">
            <p className="about-p">
              I'm a passionate third-year B.TECH Computer Science student at <strong>A.D. Patel Institute of Technology (ADIT)</strong>, Gujarat. I love turning ideas into real, scalable web applications.
            </p>
            <p className="about-p">
              My journey started with building static websites and has evolved into crafting full-stack applications using the <strong>MERN stack</strong>. I enjoy solving real-world problems and writing clean, maintainable code.
            </p>
            <p className="about-p">
              When I'm not coding, I'm exploring new technologies, contributing to projects, and sharpening my problem-solving skills.
            </p>
            <div className="stats-row">
              {[["2+", "Projects Built"], ["9.63", "CGPA"], ["2027", "Graduating"]].map(([n, l]) => (
                <div key={l} className="stat">
                  <span className="stat-num">{n}</span>
                  <span className="stat-label">{l}</span>
                </div>
              ))}
            </div>

            <div className="edu-section">
              <h4 className="edu-title">🎓 Education</h4>
              <div className="edu-timeline">
                {[
                  { year: "2021", pct: "86.4%",     school: "Auro Education Zone, Gondal",              level: "10th (SSC)" },
                  { year: "2023", pct: "91.8%",     school: "Gangotri Education Zone, Gondal",          level: "12th (HSC)" },
                  { year: "2027", pct: "B.TECH CSE", school: "A.D. Patel Institute of Technology (ADIT)", level: "Pursuing"  },
                ].map((e, i) => (
                  <div key={i} className="edu-item">
                    <div className="edu-dot" />
                    <div className="edu-info">
                      <div className="edu-row">
                        <span className="edu-level">{e.level}</span>
                        <span className="edu-pct">{e.pct}</span>
                      </div>
                      <div className="edu-school">{e.school}</div>
                      <div className="edu-year">{e.year}</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* ── SKILLS ── */}
      <section id="Skills" className="section">
        <SectionTitle label="02" title="Skills" />
        <div className="skills-grid">
          {Object.entries(SKILLS).map(([cat, items]) => (
            <div key={cat} className="skill-card">
              <h3 className="skill-cat">{cat}</h3>
              <div className="skill-tags">
                {items.map((s) => <span key={s} className="skill-tag">{s}</span>)}
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* ── PROJECTS ── */}
      <section id="Projects" className="section">
        <SectionTitle label="03" title="Projects" />
        <div className="projects-grid">
          {PROJECTS.map((p) => (
            <div
              key={p.name}
              className="project-card"
              style={{ borderTopColor: p.color }}
              onClick={() => setSelectedProject(p)}
            >
              <div className="project-header">
                <span className="project-icon">{p.icon}</span>
                <span className="project-tag" style={{ color: p.color, borderColor: p.color }}>{p.tag}</span>
              </div>
              <h3 className="project-name">{p.name}</h3>
              <p className="project-desc">{p.description}</p>
              <div className="project-techs">
                {p.tech.map((t) => (
                  <span key={t} className="project-tech"
                    style={{ background: p.color + "18", color: p.color }}>{t}</span>
                ))}
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* ── PROJECT MODAL ── */}
      {selectedProject && (
        <div className="modal-overlay" onClick={() => setSelectedProject(null)}>
          <div
            className="modal"
            style={{ borderTopColor: selectedProject.color, boxShadow: `0 0 60px ${selectedProject.color}22, 0 32px 80px rgba(0,0,0,0.7)` }}
            onClick={e => e.stopPropagation()}
          >
            <button className="modal-close" onClick={() => setSelectedProject(null)}>✕</button>
            <div className="modal-header">
              <span className="modal-icon">{selectedProject.icon}</span>
              <div>
                <span className="project-tag" style={{ color: selectedProject.color, borderColor: selectedProject.color }}>
                  {selectedProject.tag}
                </span>
                <h2 className="modal-title" style={{ color: selectedProject.color }}>{selectedProject.name}</h2>
              </div>
            </div>
            <div className="modal-divider" style={{ background: selectedProject.color + "33" }} />
            <p className="modal-desc">{selectedProject.description}</p>
            <div className="modal-section">
              <h4 className="modal-section-title" style={{ color: selectedProject.color }}>✦ Key Highlights</h4>
              <ul className="modal-list">
                {selectedProject.highlights.map((h, i) => (
                  <li key={i} className="modal-list-item">
                    <span style={{ color: selectedProject.color, marginRight: 8 }}>▸</span>{h}
                  </li>
                ))}
              </ul>
            </div>
            <div className="modal-section">
              <h4 className="modal-section-title" style={{ color: selectedProject.color }}>✦ Tech Stack</h4>
              <div className="project-techs">
                {selectedProject.tech.map((t) => (
                  <span key={t} className="modal-tech-badge"
                    style={{ background: selectedProject.color + "15", color: selectedProject.color, border: `1px solid ${selectedProject.color}40` }}>
                    {t}
                  </span>
                ))}
              </div>
            </div>
            <div className="modal-footer">
              <a href={selectedProject.github} target="_blank" rel="noopener noreferrer" className="btn-outline"
                style={{ borderColor: selectedProject.color, color: selectedProject.color, fontSize: 13 }}>
                View on GitHub ↗
              </a>
              <button className="btn-primary" style={{ background: `linear-gradient(135deg, ${selectedProject.color}, ${selectedProject.color}bb)`, fontSize: 13 }}>
                Live Demo ↗
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── CONTACT ── */}
      <section id="Contact" className="section">
        <SectionTitle label="04" title="Contact" />
        <div className="contact-wrap">
          <div className="contact-info">
            <h3 className="contact-heading">Let's build something together.</h3>
            <p className="contact-sub">Open to internships, collaborations, and cool project ideas. Drop me a message!</p>
            <div className="contact-links">
              {[
                { icon: "📧", text: "vansh.lunagariya123@gmail.com", href: "mailto:vansh.lunagariya123@gmail.com" },
                { icon: "💼", text: "Vansh Lunagariya",              href: "https://www.linkedin.com/in/vansh-lunagariya-96b3632a0/" },
                { icon: "🐙", text: "Vansh-dev1",                    href: "https://github.com/Vansh-dev1" },
              ].map(({ icon, text, href }) => (
                <a key={text} href={href} target="_blank" rel="noopener noreferrer" className="contact-link-row">
                  <span>{icon}</span>
                  <span className="contact-link-text">{text}</span>
                </a>
              ))}
            </div>
          </div>
          <form onSubmit={handleSubmit} className="contact-form">
            {sent      && <div className="form-success">✅ Message sent! I'll get back to you soon.</div>}
            {formError && <div className="form-error">⚠️ {formError}</div>}
            <input  className="form-input" placeholder="Your Name"    value={formData.name}    onChange={e => setFormData({ ...formData, name: e.target.value })}    required />
            <input  className="form-input" type="email" placeholder="Your Email"   value={formData.email}   onChange={e => setFormData({ ...formData, email: e.target.value })}   required />
            <textarea className="form-input form-textarea" placeholder="Your Message" value={formData.message} onChange={e => setFormData({ ...formData, message: e.target.value })} required />
            <button type="submit" className="btn-primary" style={{ opacity: sending ? 0.7 : 1 }} disabled={sending}>
              {sending ? "Sending..." : "Send Message →"}
            </button>
          </form>
        </div>
      </section>

      {/* ── FOOTER ── */}
      <footer className="footer">
        <span className="footer-text">Crafted with ❤️ by <span>Vansh Lunagariya</span> · ADIT College · 2025</span>
      </footer>
    </div>
  );
}

/* ─── Sub-components ─────────────────────────────────────────────────────── */
function PhotoFrame({ photo }) {
  const [expanded, setExpanded] = useState(false);
  return (
    <>
      <div className="photo-frame" onClick={() => setExpanded(true)}>
        <div className="photo-ring-1" />
        <div className="photo-ring-2" />
        <div className="photo-glow" />
        <img src={photo} alt="Vansh Lunagariya" className="profile-photo" />
      </div>
      {expanded && (
        <div className="photo-overlay" onClick={() => setExpanded(false)}>
          <div className="photo-modal" onClick={e => e.stopPropagation()}>
            <button className="modal-close" onClick={() => setExpanded(false)}>✕</button>
            <img src={photo} alt="Vansh Lunagariya" className="photo-modal-img" />
            <p className="photo-modal-name">Vansh Lunagariya</p>
            <p className="photo-modal-sub">B.TECH CSE · ADIT College, Gujarat</p>
          </div>
        </div>
      )}
    </>
  );
}

function AboutCard() {
  return (
    <div className="about-card">
      <div className="about-avatar">👨‍💻</div>
      <div className="about-badges">
        <span className="badge">ADIT College</span>
        <span className="badge">3rd Year</span>
        <span className="badge">B.TECH CSE</span>
        <span className="badge">Anand, Gujarat</span>
      </div>
    </div>
  );
}

function SectionTitle({ label, title }) {
  return (
    <div className="section-title">
      <span className="section-label">{label}.</span>
      <h2 className="section-h2">{title}</h2>
      <div className="section-line" />
    </div>
  );
}
